class AuftraegeData extends DataClass implements Insertable<AuftraegeData> {
  final int id;
  final String? aktenzeichen;
  final String art;
  final String status;
  final int? kundeId;

  /// Geschäftszeichen des Auftraggebers (bei Gericht = Gerichts-Az.).
  final String? azExtern;

  /// Betreff / Beweisthema.
  final String? betreff;
  final String? bezeichnung;
  final String? objektStrasse;
  final String? objektPlz;
  final String? objektOrt;
  final double? objektLat;
  final double? objektLon;
  final double? objektHoehe;

  /// Objektart (Einfamilienhaus, Doppelhaus, …).
  final String? objektart;
  final String? baujahr;
  final String? sachgebiet;

  /// Kategorie: Schadensgutachten / Mängelgutachten / Bewertungsgutachten / …
  final String? kategorie;

  /// JVEG-Honorargruppe: M1, M2, M3, Sonstige.
  final String? honorargruppe;
  final DateTime? eingangAm;
  final DateTime? auftragAm;

  /// Separat zum Auftragsdatum: nächster Ortstermin.
  final DateTime? ortsterminAm;

  /// Fertigstellungsfrist.
  final DateTime? fristAm;
  final DateTime? abschlussAm;
  final double? aufwandSchaetzung;
  final double? stundensatz;
  final double? kostenLimit;
  final double? kostenvorschuss;
  final String? gerichtsAktenzeichen;
  final String? gericht;
  final String? gerichtsort;

  /// Verfahrensart (Zivil, Schieds, selbst. Beweisverfahren …).
  final String? verfahrensart;
  final DateTime? akteneingangAm;
  final int? anzahlAusfertigungen;
  final int? aktenSeitenVon;
  final int? aktenSeitenBis;
  final DateTime? beweisbeschluss1;
  final DateTime? beweisbeschluss2;
  final DateTime? beweisbeschluss3;
  final String? richter;
  final String? richterAnrede;
  final String? richterBriefanrede;

  /// Streitparteien im gerichtlichen Verfahren.
  final String? klaeger;
  final String? beklagter;
  final String? beteiligteJson;

  /// Aufgaben-Array: `[{"text":"…","done":false,"doneAt":null}]`.
  final String? aufgabenJson;

  /// Schneelastzone (1 | 1a | 2 | 2a | 3) nach DIN EN 1991-1-3/NA.
  final String? schneelastzone;

  /// Geografische Schneelast in kN/m² (aus Tabelle oder Erläuterung).
  final double? schneelastKnm2;

  /// Windlastzone (1 | 2 | 3 | 4) nach DIN EN 1991-1-4/NA.
  final String? windlastzone;

