  final int id;
  final int? auftragId;

  /// Partner/Subunternehmer, der die Leistung erbracht hat. Wenn gesetzt
  /// zählt die Buchung als Fremdleistung (nicht in eigene Stunden-KPIs).
  final int? partnerId;
