  final int? gutachtenId;

  /// Optionaler Abschnitts-Schlüssel (z. B. "objektbeschreibung") — ordnet
  /// das Foto einem Gutachten-Block zu. NULL → Foto erscheint nur in der
  /// allgemeinen Lichtbildanlage am Ende.
  final String? gutachtenAbschnitt;
  final String? titel;

  /// Raum- oder Ortszuordnung im Objekt (z. B. "Schlafzimmer OG", "Fassade Ost").
  final String? raum;
  final String? beschreibung;
  final String? pfad;
  final String? mimeType;

  /// Download-URL aus Firebase Storage (wenn das Foto geclouded wurde).
  final String? storageUrl;

  /// Storage-Pfad relativ zum User-Ordner (z. B. "fotos/17134…_img.jpg").
  final String? storagePfad;

  /// Eingebettete Daten (Base64 oder raw) – optional. Nach "Bemalen" enthält
  /// dieses Feld das *bemalte* Bild; das Original bleibt in [originalDaten].
  final Uint8List? daten;

  /// Unverändertes Originalbild — wird beim ersten Bemalen gesichert,
  /// damit der Nutzer jederzeit zurückwechseln kann.
  final Uint8List? originalDaten;
  final String? originalStorageUrl;
  final String? originalStoragePfad;
  final DateTime? aufnahmeAm;
