class BenutzerData extends DataClass implements Insertable<BenutzerData> {
  final int id;
  final String? anrede;
  final String? titel;
  final String? vorname;
  final String? nachname;
  final String? firma;
  final String? strasse;
  final String? plz;
  final String? ort;
  final String? telefon;
  final String? mobil;
  final String? email;
  final String? website;
  final String? steuerNr;
  final String? ustId;
  final String? hrb;
  final String? iban;
  final String? bic;
  final String? bank;
  final String? bestellungsText;
  final double? standardStundensatz;
  final String? unterschriftPfad;
  final String? logoPfad;

  /// Profilbild als Base64 (Avatar).
  final String? profilBildBase64;
  final String? profilBildMime;

  /// Persönliche Grußformel (z. B. "Mit freundlichen Grüßen\nDr. …").
  final String? grussformel;
  final bool aktiv;

  /// Rolle im Mandanten: 'admin' | 'mitarbeiter' | 'readonly'.
  final String rolle;

  /// Komma-getrennte Liste erlaubter Module (z.B. "auftraege,rechnungen,...").
  /// `null` = Admin (alle Module). Leer = keine. Vollständige Liste = alle.
  final String? erlaubteModule;

  /// Bearbeitungsrecht pro Modul (komma-getrennt). Nur diese Module dürfen
  /// editiert werden; in anderen erlaubten Modulen ist nur Read-Only erlaubt.
  final String? bearbeitbareModule;
  final String? extras;
  final DateTime createdAt;
  final DateTime updatedAt;
  const BenutzerData({
    required this.id,
    this.anrede,
    this.titel,
    this.vorname,
    this.nachname,
    this.firma,
    this.strasse,
    this.plz,
    this.ort,
    this.telefon,
    this.mobil,
    this.email,
    this.website,
    this.steuerNr,
    this.ustId,
    this.hrb,
    this.iban,
    this.bic,
    this.bank,
    this.bestellungsText,
    this.standardStundensatz,
    this.unterschriftPfad,
    this.logoPfad,
    this.profilBildBase64,
    this.profilBildMime,
    this.grussformel,
    required this.aktiv,
    required this.rolle,
    this.erlaubteModule,
    this.bearbeitbareModule,
    this.extras,
    required this.createdAt,
    required this.updatedAt,
