      map['anrede'] = Variable<String>(anrede);
    }
    if (!nullToAbsent || titel != null) {
      map['titel'] = Variable<String>(titel);
    }
    if (!nullToAbsent || vorname != null) {
      map['vorname'] = Variable<String>(vorname);
    }
    if (!nullToAbsent || nachname != null) {
      map['nachname'] = Variable<String>(nachname);
