    extends BaseReferences<_$AppDatabase, $PartnerTable, PartnerData> {
  $$PartnerTableReferences(super.$_db, super.$_table, super.$_typedResult);

  static MultiTypedResultKey<$StundenTable, List<StundenData>>
  _stundenRefsTable(_$AppDatabase db) => MultiTypedResultKey.fromTable(
    db.stunden,
    aliasName: $_aliasNameGenerator(db.partner.id, db.stunden.partnerId),
  );

  $$StundenTableProcessedTableManager get stundenRefs {
    final manager = $$StundenTableTableManager(
      $_db,
      $_db.stunden,
    ).filter((f) => f.partnerId.id.sqlEquals($_itemColumn<int>('id')!));

    final cache = $_typedResult.readTableOrNull(_stundenRefsTable($_db));
    return ProcessedTableManager(
      manager.$state.copyWith(prefetchedData: cache),
    );
  }
}

